import React, { useState } from "react"
import { useStaticQuery, graphql } from "gatsby"
import { GatsbyImage } from "gatsby-plugin-image"
import { Swiper, SwiperSlide } from "swiper/react"
import swiperCss from "!raw-loader!sass-loader!swiper/swiper.scss"
import { Box, IconButton, Tooltip, Typography } from "@mui/material"

import NavigateNextIcon from "@mui/icons-material/NavigateNext"
import NavigateBeforeIcon from "@mui/icons-material/NavigateBefore"

import desc from "../../datasheet/showcase.yml"
import { Helmet } from "react-helmet"
import { tooltipCompProps } from "../style"
// import "../../css/waveborder.css"

const getTooltip = key => {
  if (desc[key]) {
    return (
      <>
        <Typography variant="h6">{desc[key].title}</Typography>
        {desc[key].text && (
          <Typography variant="caption">{desc[key].text}</Typography>
        )}
      </>
    )
  } else {
    return <Typography variant="caption">{key.replace(".jpg", "")}</Typography>
  }
}

const navigatorStyle = {
  color: "white",
  borderRadius: 0,
  "&:hover": {
    backgroundColor: "#3333",
    "@media (hover: none)": {
      backgroundColor: "transparent",
    },
  },
}

const Gallery = () => {
  const [swiper, setSwiper] = useState()
  const data = useStaticQuery(graphql`
    {
      showcases: allFile(filter: { relativePath: { regex: "/showcase/" } }) {
        nodes {
          childImageSharp {
            gatsbyImageData(
              height: 250
              quality: 80
              layout: FIXED
              placeholder: BLURRED
            )
          }
          name
        }
      }
    }
  `)
  if (!data?.showcases?.nodes) {
    return <div>Gallery not found</div>
    // return <SwiperSlide style={{ width: 200 }}></SwiperSlide>
  } else if (!data.showcases.nodes[0]?.childImageSharp?.gatsbyImageData) {
    return <div>Gallery not found</div>
  }

  return (
    <Box position="relative">
      <Helmet>
        <style>{swiperCss}</style>
      </Helmet>
      <Swiper
        spaceBetween={50}
        slidesPerView={"auto"}
        loop
        loopedSlides={data.showcases.nodes.length}
        grabCursor
        roundLengths
        onSwiper={swp => setSwiper(swp)}
      >
        {data.showcases.nodes.map(({ childImageSharp, name }) => {
          const fixed = {
            ...childImageSharp?.gatsbyImageData,
            originalName: "temp",
          }
          return (
            <SwiperSlide style={{ width: fixed?.width }} key={name}>
              <Tooltip
                title={getTooltip(name)}
                placement="top"
                interactive
                enterTouchDelay={150}
                componentsProps={tooltipCompProps}
              >
                <div style={{ height: "250px" }} className="wave-border">
                  <GatsbyImage image={fixed} alt={name} />
                </div>
              </Tooltip>
            </SwiperSlide>
          )
        })}
      </Swiper>
      <Box
        display="flex"
        height="100%"
        position="absolute"
        top="0"
        left="0"
        zIndex="100"
      >
        <IconButton
          sx={navigatorStyle}
          onClick={e => swiper.slidePrev()}
          children={<NavigateBeforeIcon />}
          aria-label="slide to previous slide"
        />
      </Box>
      <Box
        display="flex"
        height="100%"
        position="absolute"
        top="0"
        right="0"
        zIndex="100"
      >
        <IconButton
          sx={navigatorStyle}
          onClick={e => swiper.slideNext()}
          children={<NavigateNextIcon />}
          aria-label="slide to next slide"
        />
      </Box>
    </Box>
  )
}

export default Gallery
