import React from "react"
import { useStaticQuery, graphql } from "gatsby"
import { useMediaQuery, useTheme } from "@mui/material"
import { StaticImage } from "gatsby-plugin-image"

const Image = () => {
  const theme = useTheme()
  const big = useMediaQuery(theme.breakpoints.up("md"))
  const data = useStaticQuery(graphql`
    {
      placeholderImage: file(relativePath: { eq: "lake_orange.png" }) {
        childImageSharp {
          gatsbyImageData(height: 400, quality: 80, layout: FULL_WIDTH)
        }
      }
    }
  `)

  if (!data?.placeholderImage?.childImageSharp?.gatsbyImageData) {
    return <div>Picture not found</div>
  }

  return (
    <StaticImage
      src="../../images/lake_orange.png"
      alt="lake"
      draggable={false}
      className={big ? "wave-border" : ""}
      placeholder="blurred"
      blurredOptions={{ width: 50 }}
    />
  )
}

export default Image
