import React, { useEffect, useState } from "react"
import { graphql } from "gatsby"

import Seo from "../components/seo"
import {
  Box,
  Container,
  createTheme,
  CssBaseline,
  Grid,
  ThemeProvider,
  css,
} from "@mui/material"

import Block from "../components/homepage/block"
import Lake from "../components/homepage/lake"
import Sider from "../components/homepage/sider"
import Skill from "../components/homepage/skill"
import waveline from "../svg/wave.svg"

import Gallery from "../components/homepage/gallery"
import SocialBlock from "../components/social-media"
import RelativeProject from "../components/homepage/relative-link"
import WaveDiv from "../components/homepage/wave-divider"
import ErrorBoundary from "../components/ErrorBoundary"

// import ShowModels from '../components/model'
import loadable from "@loadable/component"

import "../css/waveborder.css"

const ShowModels = loadable(() => import("../components/homepage/model"), {
  ssr: false,
})

const styles = {
  waveDiv: css`
    background-color: transparent;
    background-image: url(${waveline});
    background-size: 10px;
    background-repeat: repeat-y;
    padding: 0px 5px;
    margin: 5rem 0rem 5rem auto;
    position: absolute;
    height: calc(100vh - 10rem);
    width: 20px;
    right: 10px;
    border: none;
    @media (max-width: 900px) {
      display: none;
    } ;
  `,
  headerBlock: css`
    display: flex;
    align-items: center;
    justify-content: center;
    @media (min-width: 899px) {
      position: sticky;
      top: 0;
      max-height: 100vh;
    } ;
  `,
  contentBlock: css`
    padding-bottom: 5rem;
    @media (min-width: 899px) {
      padding: 3rem;
    }
  `,
}

const IndexPage = () => {
  const [pageReady, setPageReady] = useState(false)
  useEffect(() => {
    setPageReady(true)
    document.body.style.backgroundColor = "#f9f6f2"
  }, [])

  return (
    <>
      <CssBaseline />
      <Seo title="Landing Page" />
      <Container
        sx={{
          background: "#f9f6f2",
          minHeight: "100vh",
        }}
        maxWidth="xxl"
        disableGutters
      >
        <Grid container style={{ minHeight: "100vh" }}>
          <Grid item xs={12} md={3} lg={2} css={styles.headerBlock}>
            <Box
              sx={{
                marginTop: "6rem",
                marginBottom: "6rem",
                display: "block",
                width: "max(30%, 7rem)",
              }}
            >
              <Sider />
            </Box>
            <hr orientation="vertical" css={styles.waveDiv} flexItem />
          </Grid>
          <Grid item xs={12} md={9} lg={10} sx={styles.contentBlock}>
            <Box py={6}>
              <Lake />
            </Box>
            <Grid container>
              <Grid item md={12} lg={6} xl={5} zeroMinWidth>
                <Block />
              </Grid>
              <Grid item md={12} lg={6} xl={7} zeroMinWidth>
                <Skill />
              </Grid>
            </Grid>
            <Box py={6}>
              <Block title="畫廊展示">
                <Gallery />
              </Block>
            </Box>
            <Block title="建置專案">
              <RelativeProject />
            </Block>
            {pageReady && (
              <Block title="三維建模">
                <ErrorBoundary>
                  <ShowModels />
                </ErrorBoundary>
              </Block>
            )}
            <WaveDiv />
            <SocialBlock />
          </Grid>
        </Grid>
      </Container>
    </>
  )
}

export const query = graphql`
  query HomePageQuery {
    site {
      siteMetadata {
        description
      }
    }
  }
`

const theme = createTheme()
const IndexPageWrapper = () => (
  <ThemeProvider theme={theme}>
    <IndexPage />
  </ThemeProvider>
)

export default IndexPageWrapper
