import {
  Card,
  CardActionArea,
  CardContent,
  Grid,
  Typography,
} from "@mui/material"
import { useStaticQuery, withPrefix, graphql } from "gatsby"
import React from "react"
import { GatsbyImage } from "gatsby-plugin-image"
import { find, map } from "lodash"
import pages from "../../datasheet/relative-pages.yml"
// import "../../css/waveborder.css"

const Relative = ({ image, href, title = "Relative", desc = "" }) => {
  return (
    <Grid item sm={12} lg={6} xl={4}>
      <Card
        sx={{
          borderRadius: "10px",
          border: "none",
          background: "#f9f6f2",
          color: "#8a446b",
        }}
        variant="outlined"
      >
        <CardActionArea
          sx={{ padding: 0.5 }}
          component="a"
          href={href}
          rel="noopener"
        >
          {image}
          {/* <Divider></Divider> */}
          <CardContent>
            <Typography gutterBottom variant="h6" component="h2">
              {title}
            </Typography>
            <Typography variant="body2" color="textSecondary" component="p">
              {desc}
            </Typography>
          </CardContent>
        </CardActionArea>
      </Card>
    </Grid>
  )
}

const RelativeLink = () => {
  const data = useStaticQuery(graphql`
    {
      relative: allFile(filter: { relativePath: { regex: "/relative/" } }) {
        nodes {
          name
          childImageSharp {
            gatsbyImageData(width: 480, quality: 75, layout: CONSTRAINED)
          }
        }
      }
    }
  `)
  const pagesData = map(pages, ({ href, prefix, image, desc }, title) => {
    return {
      title,
      desc,
      fluid: find(data?.relative?.nodes, { name: image })?.childImageSharp
        ?.gatsbyImageData,
      href: prefix ? withPrefix(href) : href,
    }
  })

  return (
    <Grid container spacing={2}>
      {pagesData.map(({ fluid, ...rest }) => {
        return (
          <Relative
            image={
              fluid && (
                <GatsbyImage image={fluid} className="wave-border" alt="name" />
              )
            }
            key={rest.title}
            {...rest}
          />
        )
      })}
    </Grid>
  )
}

export default RelativeLink
