import { Tooltip, Typography } from "@mui/material"
import makeStyles from "@mui/styles/makeStyles"
import React from "react"

import skillList from "../../datasheet/skill_list.yml"

import iconlist from "./skill_icons"
import Block from "./block"
import { tooltipCompProps } from "../style"
import { css } from "@mui/material"

const styles = {
  chunk: css`
    display: flex;
    margin-bottom: 1.5rem;
    flex-direction: column;
  `,
  groupTitle: css`
    margin: 0;
    margin-bottom: 0.5rem;
    color: #666;
    font-weight: 300;
    letter-spacing: 0.02em;
    font-size: small;
  `,
  group: css`
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
  `,
  nameSet: css`
    display: flex;
    align-items: center;
    font-weight: 700;
    font-style: italic;
  `,
  svg: css`
    height: 1.25em;
    max-width: 1.6em;
    margin-right: 0.25rem;
  `,
}

const SkillTooltipTitle = ({ skill }) => {
  return (
    <>
      <Typography variant="h6">{skill.name}</Typography>
      {skill.desc && <Typography variant="caption">{skill.desc}</Typography>}
    </>
  )
}

const SkillBasic = ({ skill, svg, children }) => {
  return (
    <Tooltip
      title={<SkillTooltipTitle skill={skill} />}
      enterTouchDelay={50}
      interactive
      componentsProps={tooltipCompProps}
    >
      <div css={styles.nameSet}>
        <img src={iconlist[svg]} alt={svg} css={styles.svg} />
        {children}
      </div>
    </Tooltip>
  )
}

const Skill = ({ data }) => {
  const { category, subskills } = data
  return (
    <div css={styles.chunk}>
      <h3 css={styles.groupTitle}>{category}</h3>
      <div css={styles.group}>
        {subskills.map(skill => {
          return (
            <SkillBasic key={skill.name} skill={skill} svg={skill.svg}>
              {skill.name}
            </SkillBasic>
          )
        })}
      </div>
    </div>
  )
}

const skill = () => (
  <Block title="個人技能">
    {skillList.map(data => {
      return <Skill data={data} key={data.category} />
    })}
  </Block>
)

export default skill
